import React, { useState, useEffect, useCallback } from "react";
import axios from "axios";
import { ResponsiveContainer, AreaChart, Area, YAxis } from "recharts";
import { Bitcoin, Coins, CircleDot, Database, Smartphone, XCircle } from "lucide-react";
import "../../styles/financecoin.css";

// Yapılandırmayı dışarıda tanımlıyoruz
const COIN_CONFIGS = {
  BTCTRY: { name: "BITCOIN", symbol: "BTC", icon: Bitcoin, color: "#F7931A" },
  ETHTRY: { name: "ETHEREUM", symbol: "ETH", icon: Coins, color: "#627EEA" },
  SOLTRY: { name: "SOLANA", symbol: "SOL", icon: Smartphone, color: "#14F195" },
  BNBTRY: { name: "BINANCE COIN", symbol: "BNB", icon: CircleDot, color: "#F3BA2F" },
  ADATRY: { name: "CARDANO", symbol: "ADA", icon: Database, color: "#0033AD" },
  XRPTRY: { name: "XRP", symbol: "XRP", icon: XCircle, color: "#ffffff" }
};

const CryptoBox = ({ coin }) => {
  const Icon = coin.icon;
  const isPositive = coin.dailyPercent >= 0;

  return (
    <div className="crypto-item-box">
      <div className="coin-left-section">
        <div 
          className="coin-icon-wrapper" 
          style={{ background: `linear-gradient(135deg, ${coin.color}33, ${coin.color}11)` }}
        >
          <Icon size={28} color={coin.color} />
        </div>
        <div className="coin-details">
          <h3 className="coin-title">{coin.name} ({coin.symbol})</h3>
          <div className="price-info">
            <span className="coin-price">{parseFloat(coin.last).toLocaleString("tr-TR")} ₺</span>
            <span className={`coin-change ${isPositive ? "up" : "down"}`}>
              {isPositive ? "+" : ""}{coin.dailyPercent.toFixed(2)}%
            </span>
          </div>
        </div>
      </div>

      <div className="coin-right-section">
        <ResponsiveContainer width="100%" height={60}>
          <AreaChart data={coin.history}>
            <defs>
              <linearGradient id={`color-${coin.symbol}`} x1="0" y1="0" x2="0" y2="1">
                <stop offset="5%" stopColor={coin.color} stopOpacity={0.3} />
                <stop offset="95%" stopColor={coin.color} stopOpacity={0} />
              </linearGradient>
            </defs>
            <YAxis hide domain={["dataMin", "dataMax"]} />
            <Area
              type="monotone"
              dataKey="price"
              stroke={coin.color}
              fill={`url(#color-${coin.symbol})`}
              strokeWidth={2}
              dot={false}
              isAnimationActive={true}
            />
          </AreaChart>
        </ResponsiveContainer>
      </div>
    </div>
  );
};

export default function FinanceCoin() {
  const [data, setData] = useState([]);
  const [loading, setLoading] = useState(true);

  const fetchData = useCallback(async () => {
    try {
      // 1. Adım: Tüm Ticker verilerini tek seferde çekiyoruz (BtcTürk)
      const tickerRes = await axios.get("https://api.btcturk.com/api/v2/ticker");
      const filteredPairs = tickerRes.data.data.filter(pair => COIN_CONFIGS[pair.pair]);

      // 2. Adım: Her coin için grafik verisini alıyoruz
      const fullCoinsData = await Promise.all(
        filteredPairs.map(async (coin) => {
          try {
            // Son 24 saatlik grafik verisi (1 saatlik mumlar)
            const graphRes = await axios.get(
              `https://api.btcturk.com/api/v2/graph/history/v1/klines?symbol=${coin.pair}&resolution=60`
            );
            
            // Veri gelmezse boş dizi dön
            const history = Array.isArray(graphRes.data) 
              ? graphRes.data.map(item => ({ price: item.c })) 
              : [];

            return {
              ...coin,
              ...COIN_CONFIGS[coin.pair],
              history: history
            };
          } catch (e) {
            return { ...coin, ...COIN_CONFIGS[coin.pair], history: [] };
          }
        })
      );

      setData(fullCoinsData);
      setLoading(false);
    } catch (err) {
      console.error("Veri çekme hatası:", err);
      // Hata olsa bile loading'i kapat ki kullanıcı sonsuz döngüde kalmasın
      setLoading(false); 
    }
  }, []);

  useEffect(() => {
    fetchData();
    const interval = setInterval(fetchData, 20000); // 20 saniyede bir güncelle
    return () => clearInterval(interval);
  }, [fetchData]);

  if (loading) return <div className="loader">Veriler Yükleniyor...</div>;

  return (
    <div className="market-insight-wrapper">
      <div className="market-header">
        <h2 className="market-main-title">CRYPTO MARKET INSIGHTS</h2>
        <div className="live-indicator">
          <span>●</span> CANLI
        </div>
      </div>

      <div className="crypto-boxes-container">
        {data.length > 0 ? (
          data.map((coin) => <CryptoBox key={coin.pair} coin={coin} />)
        ) : (
          <div className="error-msg">Veri alınamadı. Lütfen internetinizi veya CORS ayarlarını kontrol edin.</div>
        )}
      </div>
    </div>
  );
}
